import {useEffect, useState} from "react";
import UserService from "../services/user.service";
import EventBus from "../common/EventBus";
import {Link, useNavigate} from "react-router-dom";

import Form from "react-validation/build/form";
import Input from "react-validation/build/input";
import {addStoryGenre} from "../actions/auth";
import {useDispatch} from "react-redux";
import axios from "axios";

const required = (value) => {
    if (!value) {
        return (
            <div className="alert alert-danger">
                Trường này là bắt buộc!
            </div>
        )
    }
}
const BoardAdmin = () => {
    const [content, setContent] = useState("");
    const [tenTheLoai, setTenTheLoai] = useState("");
    const [mota, setMota] = useState("");
    const [errorMessage, setErrorMessage] = useState('');
    const dispatch = useDispatch();
    const navigate = useNavigate();

    useEffect(() => {
        UserService.getAdminBoard().then(
            (response) => {
                setContent(response.data);
            },
            (error) => {
                const _content = (error.response && error.response.data && error.response.data.message) || error.message || error.toString();
                setContent(_content);
                if (error.response && error.response.status === 401) {
                    EventBus.dispatch("logout");
                }
            }
        );
    }, []);
    const onChangeStoryGenreName = (e) => {
        const storyGenreName = e.target.value;
        setTenTheLoai(storyGenreName);
    }
    const onChangeDescription = (e) => {
        const description = e.target.value;
        setMota(description);
    }
    const handleSubmit = async (e) => {
        const token = localStorage.getItem("token");
        setErrorMessage('');
        e.preventDefault();
        // dispatch(addStoryGenre(storyGenreName, description))
        //     .then(() => {
        //         alert("Thêm thể loại truyện thành công!");
        //         window.location.reload();
        //     })
        //     .catch(() => {
        //         alert("Thêm thể loại truyện thất bại!");
        //     });
        try {
            const response = await axios.post(
                'http://localhost:8080/api/admin/theloais',
                {tenTheLoai, mota},
                {
                    headers: {
                        Authorization: `Bearer ${token}`, // Định dạng đúng headers với Authorization
                    },
                }
            );
            console.log('Tạo thể loại truyện thành công: ', response);
            setTenTheLoai("");
            setMota("");
        } catch (error) {
            console.log(error)
            if (error.response) {
                setErrorMessage(error.response.data.message);
            } else {
                setErrorMessage('Đã xảy ra lỗi không xác định.');
            }
        }
    }
    return (
        <div className="container">
            <div className="container bg-dark p-5">
                <span> <Link to="/" className="text-decoration-none">Trang chủ </Link>
                    <i className="bi bi-chevron-double-right"></i>
                    <span className="text-warning">Thể loại truyện</span>
                </span>
                <h2 className="text-warning text-center">Thể loại truyện</h2>
                {errorMessage && <p className="container alert alert-danger alert-dismissible fade show p-2" role="alert">
                    {errorMessage}
                    <button type="button" className="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>
                </p>}
                <Form onSubmit={handleSubmit} className="container p-4">
                    <div className="mb-3 mt-3">
                        <label htmlFor="storyGenreName">Tên thể loại:</label>
                        <Input
                            type="text"
                            className="form-control"
                            id="storyGenreName"
                            placeholder="Nhập tên thể loại truyện"
                            name="storyGenreName"
                            value={tenTheLoai}
                            onChange={onChangeStoryGenreName}
                            validations={[required]}
                        />
                    </div>
                    <div className="mb-3">
                        <label htmlFor="description" className="form-label">Mô tả: </label>
                        <textarea
                            required
                            className="form-control"
                            id="description"
                            value={mota}
                            name="description"
                            onChange={onChangeDescription}
                            validations={[required]}
                            rows="3">
                        </textarea>
                    </div>
                    <button type="submit" className="btn btn-outline-warning form-control mb-3">
                        <span>Thêm</span>
                    </button>
                </Form>
                <div className="container mt-3">
                    <h3>Danh sách thể loại truyện</h3>
                    <table className="table table-dark table-hover table-bordered overflow-y: hidden text-center">
                        <thead>
                        <tr>
                            <th>Tên thể loại truyện</th>
                            <th>Cập nhật</th>
                            <th>Xóa</th>
                        </tr>
                        </thead>
                        <tbody>
                        <tr>
                            <td>Action</td>
                            <td>
                                <button className="btn btn-outline-success"><i className="bi bi-pencil-square"></i>
                                </button>
                            </td>
                            <td>
                                <button className="btn btn-outline-danger"><i className="bi bi-trash"></i></button>
                            </td>
                        </tr>
                        <tr>
                            <td>Adventure</td>
                            <td>
                                <button className="btn btn-outline-success"><i className="bi bi-pencil-square"></i>
                                </button>
                            </td>
                            <td>
                                <button className="btn btn-outline-danger"><i className="bi bi-trash"></i></button>
                            </td>
                        </tr>
                        <tr>
                            <td>Comedy</td>
                            <td>
                                <button className="btn btn-outline-success"><i className="bi bi-pencil-square"></i>
                                </button>
                            </td>
                            <td>
                                <button className="btn btn-outline-danger"><i className="bi bi-trash"></i></button>
                            </td>
                        </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default BoardAdmin;
